    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        // fetchTicker, fetchTickers
        //
        //     {
        //         "opening_price":"227100",
        //         "closing_price":"228400",
        //         "min_price":"222300",
        //         "max_price":"230000",
        //         "units_traded":"82618.56075337",
        //         "acc_trade_value":"18767376138.6031",
        //         "prev_closing_price":"227100",
        //         "units_traded_24H":"151871.13484676",
        //         "acc_trade_value_24H":"34247610416.8974",
        //         "fluctate_24H":"8700",
        //         "fluctate_rate_24H":"3.96",
        //         "date":"1587710327264", // fetchTickers inject this
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(ticker, "date");
        Object symbol = this.safeSymbol(null, market);
        Object open = this.safeString(ticker, "opening_price");
        Object close = this.safeString(ticker, "closing_price");
        Object baseVolume = this.safeString(ticker, "units_traded_24H");
        Object quoteVolume = this.safeString(ticker, "acc_trade_value_24H");
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", BithumbCore.this.iso8601(timestamp) );
            put( "high", BithumbCore.this.safeString(ticker, "max_price") );
            put( "low", BithumbCore.this.safeString(ticker, "min_price") );
            put( "bid", BithumbCore.this.safeString(ticker, "buy_price") );
            put( "bidVolume", null );
            put( "ask", BithumbCore.this.safeString(ticker, "sell_price") );
            put( "askVolume", null );
            put( "vwap", null );
            put( "open", open );
            put( "close", close );
            put( "last", close );
            put( "previousClose", null );
            put( "change", null );
            put( "percentage", null );
            put( "average", null );
            put( "baseVolume", baseVolume );
            put( "quoteVolume", quoteVolume );
            put( "info", ticker );
        }}, market);
    }

