    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // fetchTrades (public)
        //
        //     {
        //         "transaction_date":"2020-04-23 22:21:46",
        //         "type":"ask",
        //         "units_traded":"0.0125",
        //         "price":"8667000",
        //         "total":"108337"
        //     }
        //
        // fetchOrder (private)
        //
        //     {
        //         "transaction_date": "1572497603902030",
        //         "price": "8601000",
        //         "units": "0.005",
        //         "fee_currency": "KRW",
        //         "fee": "107.51",
        //         "total": "43005"
        //     }
        //
        // a workaround for their bug in date format, hours are not 0-padded
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = null;
        Object transactionDatetime = this.safeString(trade, "transaction_date");
        if (Helpers.isTrue(!Helpers.isEqual(transactionDatetime, null)))
        {
            Object parts = Helpers.split(transactionDatetime, " ");
            Object numParts = Helpers.getArrayLength(parts);
            if (Helpers.isTrue(Helpers.isGreaterThan(numParts, 1)))
            {
                Object transactionDate = Helpers.GetValue(parts, 0);
                Object transactionTime = Helpers.GetValue(parts, 1);
                if (Helpers.isTrue(Helpers.isLessThan(((String)transactionTime).length(), 8)))
                {
                    transactionTime = Helpers.add("0", transactionTime);
                }
                timestamp = this.parse8601(Helpers.add(Helpers.add(transactionDate, " "), transactionTime));
            } else
            {
                timestamp = this.safeIntegerProduct(trade, "transaction_date", 0.001);
            }
        }
        if (Helpers.isTrue(!Helpers.isEqual(timestamp, null)))
        {
            timestamp = Helpers.subtract(timestamp, Helpers.multiply(9, 3600000)); // they report UTC + 9 hours, server in Korean timezone
        }
        Object type = null;
        Object side = this.safeString(trade, "type");
        side = ((Helpers.isTrue((Helpers.isEqual(side, "ask"))))) ? "sell" : "buy";
        Object id = this.safeString(trade, "cont_no");
        market = this.safeMarket(null, market);
        Object priceString = this.safeString(trade, "price");
        Object amountString = this.fixCommaNumber(this.safeString2(trade, "units_traded", "units"));
        Object costString = this.safeString(trade, "total");
        Object fee = null;
        Object feeCostString = this.safeString(trade, "fee");
        if (Helpers.isTrue(!Helpers.isEqual(feeCostString, null)))
        {
            Object feeCurrencyId = this.safeString(trade, "fee_currency");
            Object feeCurrencyCode = this.commonCurrencyCode(((String)feeCurrencyId));
            final Object finalFeeCostString = feeCostString;
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", finalFeeCostString );
                put( "currency", feeCurrencyCode );
            }};
        }
        final Object finalTimestamp = timestamp;
        final Object finalMarket = market;
        final Object finalSide = side;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "id", id );
            put( "info", trade );
            put( "timestamp", finalTimestamp );
            put( "datetime", BithumbCore.this.iso8601(finalTimestamp) );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "order", null );
            put( "type", type );
            put( "side", finalSide );
            put( "takerOrMaker", null );
            put( "price", priceString );
            put( "amount", amountString );
            put( "cost", costString );
            put( "fee", finalFee );
        }}, market);
    }

