    /**
     * @method
     * @name bithumb#createOrder
     * @description create a trade order
     * @see https://apidocs.bithumb.com/v1.2.0/reference/%EC%A7%80%EC%A0%95%EA%B0%80-%EC%A3%BC%EB%AC%B8%ED%95%98%EA%B8%B0
     * @see https://apidocs.bithumb.com/v1.2.0/reference/%EC%8B%9C%EC%9E%A5%EA%B0%80-%EB%A7%A4%EC%88%98%ED%95%98%EA%B8%B0
     * @see https://apidocs.bithumb.com/v1.2.0/reference/%EC%8B%9C%EC%9E%A5%EA%B0%80-%EB%A7%A4%EB%8F%84%ED%95%98%EA%B8%B0
     * @param {string} symbol unified symbol of the market to create an order in
     * @param {string} type 'market' or 'limit'
     * @param {string} side 'buy' or 'sell'
     * @param {float} amount how much of currency you want to trade in units of base currency
     * @param {float} [price] the price at which the order is to be fulfilled, in units of the quote currency, ignored in market orders
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [order structure]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> createOrder(Object symbol, Object type2, Object side2, Object amount, Object... optionalArgs)
    {
        final Object type3 = type2;
        final Object side3 = side2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object type = type3;
            Object side = side3;
            Object price = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "order_currency", Helpers.GetValue(market, "id") );
                put( "payment_currency", Helpers.GetValue(market, "quote") );
                put( "units", amount );
            }};
            Object method = "privatePostTradePlace";
            if (Helpers.isTrue(Helpers.isEqual(type, "limit")))
            {
                Helpers.addElementToObject(request, "price", price);
                Helpers.addElementToObject(request, "type", ((Helpers.isTrue((Helpers.isEqual(side, "buy"))))) ? "bid" : "ask");
            } else
            {
                method = Helpers.add("privatePostTradeMarket", this.capitalize(((String)side)));
            }
            Object response = ((java.util.concurrent.CompletableFuture<Object>)Helpers.callDynamically(this, method, new Object[] { this.extend(request, parameters) })).join();
            Object id = this.safeString(response, "order_id");
            if (Helpers.isTrue(Helpers.isEqual(id, null)))
            {
                throw new InvalidOrder((String)Helpers.add(this.id, " createOrder() did not return an order id")) ;
            }
            final Object finalType = type;
            final Object finalSide = side;
            final Object finalId = id;
            return this.safeOrder(new java.util.HashMap<String, Object>() {{
                put( "info", response );
                put( "symbol", symbol );
                put( "type", finalType );
                put( "side", finalSide );
                put( "id", finalId );
            }}, market);
        });

    }

